(double r, double g, double b) _cpu_magnet_type_1(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  // Ported from shaders/escape_time_family/newton_and_orthogonal/magnet_maps/magnet1_gpu.frag
  final cx = x;
  final cy = y;
  double zx = 0.0;
  double zy = 0.0;
  final bailout2 = bailout * bailout;
  int it = 0;

  while (it < iterations) {
    final mag2 = zx * zx + zy * zy;
    if (mag2 > bailout2) break;

    // z = ((z^2 + c - 1) / (2z + c - 2))^2
    final z2x = zx * zx - zy * zy;
    final z2y = 2.0 * zx * zy;

    final numx = z2x + cx - 1.0;
    final numy = z2y + cy;
    final denx = 2.0 * zx + cx - 2.0;
    final deny = 2.0 * zy + cy;

    final q = _cdivSafe(numx, numy, denx, deny);
    final qx = q.$1;
    final qy = q.$2;

    zx = qx * qx - qy * qy;
    zy = 2.0 * qx * qy;
    it++;
  }

  if (it >= iterations) return _insideColor;
  final mag2 = zx * zx + zy * zy;
  final t = _smoothEscape(it: it, iterations: iterations, mag2: mag2 + 1.0);
  return _palette(t);
}

(double r, double g, double b) _cpu_magnet_type_2(
  double x,
  double y,
  int iterations,
  double bailout,
