  // Ported from shaders/escape_time_family/newton_and_orthogonal/magnet_maps/magnet2_gpu.frag
  final cx = x;
  final cy = y;
  double zx = 0.0;
  double zy = 0.0;
  final bailout2 = bailout * bailout;
