    final numy = z3y + 3.0 * c1zy + c2y;

    final denx = 3.0 * z2x + 3.0 * c2zx + c2x - cx + 3.0;
    final deny = 3.0 * z2y + 3.0 * c2zy + c2y - cy;

    final q = _cdivSafe(numx, numy, denx, deny);
