  // Ported from shaders/escape_time_family/newton_and_orthogonal/magnet_maps/magnet3_gpu.frag
  final px = x;
  final py = y;
  double zx = px;
  double zy = py;

  const kAx = 0.42;
  const kAy = -0.18;
  const kBx = -0.31;
  const kBy = 0.24;
  const kCx = 0.73;
  const kCy = 0.11;
  const kDx = -0.26;
  const kDy = -0.39;
  const kEx = 0.85;
  const kEy = 0.07;

  final bailout2 = bailout * bailout;
  int it = 0;

  while (it < iterations) {
    final mag2 = zx * zx + zy * zy;
    if (mag2 > bailout2) break;

    final z2x = zx * zx - zy * zy;
    final z2y = 2.0 * zx * zy;
    final z3x = z2x * zx - z2y * zy;
    final z3y = z2x * zy + z2y * zx;
    final z4x = z2x * z2x - z2y * z2y;
    final z4y = 2.0 * z2x * z2y;

    // num = z4 + kA*z2 + kB
